import { Modal } from 'react-bootstrap';
import React from 'react';

function CBitsModal(props) {
  const { image } = props;
  return (
    <Modal
      {...props}
      size="md"
      aria-labelledby="contained-modal-title-vcenter"
      centered
    >
      <Modal.Header closeButton style={{ borderBottom: '0px' }}>
        <Modal.Title id="contained-modal-title-vcenter">
          CardanoBits #{image.number}
        </Modal.Title>
      </Modal.Header>
      <Modal.Body style={{ paddingBottom: '0px' }}>
        <div key={image.number}>
          <img className="img-fluid" src={image.link} alt={['mage.tags']} />
        </div>
      </Modal.Body>
      <Modal.Footer
        style={{ borderTop: '20px solid black' }}
        className="float-left"
      >
        {image.tags.map(
          (tag, i) => (
            <p className="modal-tags" key={i}>
              {' '}
              {tag.name + ' (' + tag.rarity + '%)'}{' '}
            </p>
          ),
          <br />
        )}
      </Modal.Footer>
    </Modal>
  );
}
export default CBitsModal;
